const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const bcrypt = require('bcrypt');

const app = express();
const server = http.createServer(app);
const io = socketIo(server);

const users = {};

app.use(express.json());

// Mock user database
const mockUsers = {
  'user1': '$2b$10$dGhlIHNhbXBsZSBub25jZQ==', // Password: example
  'user2': '$2b$10$eW91ciB3aXRoIGEgcGFzc3dvcmQ=' // Password: your with a password
};

io.use((socket, next) => {
  const authHeader = socket.handshake.headers.authorization;
  if (!authHeader) return next(new Error('Authentication required'));

  const token = authHeader.split(' ')[1];
  if (token !== 'valid_token') return next(new Error('Invalid token'));

  next();
});

io.on('connection', (socket) => {
  console.log('New player connected');

  socket.on('login', async (data, callback) => {
    const { username, password } = data;
    if (!username || !password) return callback({ error: 'Username and password are required' });

    if (!mockUsers[username]) return callback({ error: 'User not found' });

    const isPasswordValid = await bcrypt.compare(password, mockUsers[username]);
    if (!isPasswordValid) return callback({ error: 'Invalid password' });

    users[socket.id] = { username, score: 0 };
    socket.emit('loginSuccess', { message: 'Logged in successfully' });
    callback(null);
  });

  socket.on('move', (data, callback) => {
    const { move } = data;
    if (!move) return callback({ error: 'Move is required' });

    // Validate and process the move
    // ...

    users[socket.id].score += 1; // Example score increment

    io.emit('updateScore', { username: users[socket.id].username, score: users[socket.id].score });
    callback(null);
  });

  socket.on('disconnect', () => {
    console.log('Player disconnected');
    delete users[socket.id];
  });
});

server.listen(3000, () => {
  console.log('Server is running on port 3000');
});